/* JS — in the code_evidence builder */
function syncFade(){preWrap.classList.toggle("has-more", pre.scrollLeft+pre.clientWidth < pre.scrollWidth-1);}
pre.addEventListener("scroll",syncFade,{passive:true});
window.addEventListener("resize",syncFade);
requestAnimationFrame(syncFade);

requestAnimationFrame(function(){
  if(pre.scrollWidth > pre.clientWidth+1 || pre.scrollHeight > pre.clientHeight+1){
    pre.setAttribute("tabindex","0");
    pre.setAttribute("role","region");
    pre.setAttribute("aria-label",(ce.location||"code evidence")+" — scrollable");
  }
});

@media print{
  figure.code pre, figure.code code{white-space:pre-wrap; overflow-wrap:break-word}
  figure.code code{display:block; padding-right:0}
}

